import React, { useState } from 'react';
import axios from 'axios';
import Editor from '@monaco-editor/react';
import { 
  Upload, FileCode, ShieldCheck, RefreshCw, 
  Eye, EyeOff, BarChart3, Terminal, Activity, ShieldAlert
} from 'lucide-react';

import RiskProfile from './components/RiskProfile';
import StatisticsTab from './components/StatisticsTab';

function App() {
  const [activeTab, setActiveTab] = useState("analysis");
  const [viewMode, setViewMode] = useState("original");
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState(null);
  const [code, setCode] = useState("// Upload PHP script to begin...");
  const [results, setResults] = useState(null);
  const [editorRef, setEditorRef] = useState(null);

  const handleFileUpload = (e) => {
    const uploadedFile = e.target.files[0];
    if (uploadedFile) {
      setFile(uploadedFile);
      const reader = new FileReader();
      reader.onload = (e) => setCode(e.target.result);
      reader.readAsText(uploadedFile);
    }
  };

  const analyzeMalware = async () => {
    if (!file) return;
    setLoading(true);
    const formData = new FormData();
    formData.append("file", file);
    try {
      const response = await axios.post("http://localhost:8000/scan", formData);
      setResults(response.data.results);
    } catch (error) {
      alert("Backend Connection Failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Top Header */}
      <nav className="h-20 border-b border-slate-800 bg-[#1e293b]/50 backdrop-blur-md px-8 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-4">
          <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-500/20">
            <ShieldCheck className="text-white" size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold text-white tracking-tight">PHPSentinel</h1>
            <div className="flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
              <span className="text-[10px] text-slate-400 font-mono uppercase tracking-tighter">AI Engine Active</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <label className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-lg cursor-pointer transition-all text-sm font-medium">
            <Upload size={16} className="text-blue-400" />
            <span>{file ? file.name : "Select File"}</span>
            <input type="file" className="hidden" onChange={handleFileUpload} accept=".php" />
          </label>
          <button 
            onClick={analyzeMalware}
            disabled={loading}
            className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-sm font-bold flex items-center gap-2 disabled:opacity-50 transition-all"
          >
            {loading ? <RefreshCw className="animate-spin" size={16} /> : <Activity size={16} />}
            {loading ? "Analyzing..." : "Scan Payload"}
          </button>
        </div>
      </nav>

      <div className="flex flex-1 max-w-[1800px] mx-auto w-full p-6 gap-6">
        {/* Sidebar Nav */}
        <aside className="w-64 flex flex-col gap-2">
          <button 
            onClick={() => setActiveTab("analysis")}
            className={`flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all ${activeTab === 'analysis' ? 'bg-blue-600/10 text-blue-400 border border-blue-600/20' : 'text-slate-500 hover:bg-slate-800'}`}
          >
            <Terminal size={18} /> Threat Detection
          </button>
          <button 
            onClick={() => setActiveTab("stats")}
            className={`flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all ${activeTab === 'stats' ? 'bg-blue-600/10 text-blue-400 border border-blue-600/20' : 'text-slate-500 hover:bg-slate-800'}`}
          >
            <BarChart3 size={18} /> Model Analytics
          </button>
          <div className="mt-auto p-4 bg-slate-900/50 rounded-2xl border border-slate-800">
            <div className="flex items-center gap-2 text-blue-400 mb-2">
              <ShieldAlert size={14} />
              <span className="text-[10px] font-bold uppercase">Thesis Status</span>
            </div>
            <p className="text-[11px] text-slate-500 leading-relaxed">CodeBERT fine-tuned for PHP Webshell Detection.</p>
          </div>
        </aside>

        {/* Main Workspace */}
        <main className="flex-1">
          {activeTab === "analysis" ? (
            <div className="grid grid-cols-12 gap-6 h-full">
              <div className="col-span-8 bg-[#1e293b] rounded-3xl border border-slate-800 overflow-hidden flex flex-col shadow-2xl">
                <div className="px-6 py-3 border-b border-slate-800 flex justify-between items-center bg-slate-900/30">
                  <div className="flex items-center gap-2">
                    <FileCode size={16} className="text-slate-500" />
                    <span className="text-xs font-mono text-slate-400 uppercase tracking-widest">{viewMode}</span>
                  </div>
                  <div className="flex bg-slate-900 rounded-lg p-1 border border-slate-800">
                    <button onClick={() => setViewMode("original")} className={`px-3 py-1 text-[10px] font-bold rounded-md ${viewMode === 'original' ? 'bg-slate-700 text-white' : 'text-slate-500'}`}>RAW</button>
                    <button onClick={() => setViewMode("normalized")} className={`px-3 py-1 text-[10px] font-bold rounded-md ${viewMode === 'normalized' ? 'bg-slate-700 text-white' : 'text-slate-500'}`}>CLEAN</button>
                  </div>
                </div>
                <div className="flex-1">
                  <Editor
                    theme="vs-dark"
                    defaultLanguage="php"
                    value={results ? (viewMode === "original" ? results.original_code : results.normalized_code) : code}
                    onMount={(editor) => setEditorRef(editor)}
                    options={{ minimap: { enabled: false }, fontSize: 14, padding: { top: 20 } }}
                  />
                </div>
              </div>
              <div className="col-span-4">
                {results ? <RiskProfile data={results} /> : (
                  <div className="h-full border-2 border-dashed border-slate-800 rounded-3xl flex flex-col items-center justify-center p-8 opacity-40">
                    <ShieldCheck size={48} className="mb-4" />
                    <p className="text-sm font-medium">Ready for Intelligence Input</p>
                  </div>
                )}
              </div>
            </div>
          ) : (
            <StatisticsTab />
          )}
        </main>
      </div>
    </div>
  );
}

export default App;
